public class FibTabulation {

    public long fibTable(int n) {
        if (n <= 1) return n;
        long[] dp = new long[n + 1];
        dp[0] = 0; dp[1] = 1;
        // TODO: for i from 2 to n: dp[i] = dp[i-1] + dp[i-2]
        return dp[n];
    }

    public long fibOptimized(int n) {
        if (n <= 1) return n;
        long prev2 = 0, prev1 = 1;
        // TODO: loop n-1 times, updating prev2 and prev1
        return prev1;
    }

    public static void main(String[] args) {
        FibTabulation ft = new FibTabulation();
        for (int n : new int[]{0, 1, 5, 10, 20, 30}) {
            long t = ft.fibTable(n);
            long o = ft.fibOptimized(n);
            System.out.printf("fib(%2d) = %8d, optimized = %8d, match = %b%n", n, t, o, t==o);
        }
    }
}

public class LCSTabulation {

    public int lcsLength(String a, String b) {
        int m = a.length(), n = b.length();
        int[][] dp = new int[m+1][n+1];
        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                if (a.charAt(i-1) == b.charAt(j-1)) {
                    // TODO: dp[i][j] = dp[i-1][j-1] + 1
                } else {
                    // TODO: dp[i][j] = Math.max(dp[i-1][j], dp[i][j-1])
                }
            }
        }
        return dp[m][n];
    }

    public String lcsString(String a, String b) {
        int m = a.length(), n = b.length();
        int[][] dp = new int[m+1][n+1];
        for (int i=1;i<=m;i++) for (int j=1;j<=n;j++)
            dp[i][j] = (a.charAt(i-1)==b.charAt(j-1)) ? dp[i-1][j-1]+1 : Math.max(dp[i-1][j],dp[i][j-1]);

        // Backtrack to find the LCS string
        StringBuilder sb = new StringBuilder();
        int i = m, j = n;
        while (i > 0 && j > 0) {
            if (a.charAt(i-1) == b.charAt(j-1)) {
                sb.append(a.charAt(i-1));
                i--; j--;
            } else if (dp[i-1][j] > dp[i][j-1]) {
                i--;
            } else {
                j--;
            }
        }
        return sb.reverse().toString();
    }

    public static void main(String[] args) {
        LCSTabulation lcs = new LCSTabulation();
        System.out.println("LCS length: " + lcs.lcsLength("AGGTAB", "GXTXAYB"));
        System.out.println("LCS string: " + lcs.lcsString("AGGTAB", "GXTXAYB"));
        System.out.println("LCS length: " + lcs.lcsLength("ABCBDAB", "BDCABA"));
        System.out.println("LCS string: " + lcs.lcsString("ABCBDAB", "BDCABA"));
    }
}

import java.util.*;

public class KnapsackTabulation {

    public int maxValue(int[] weights, int[] values, int capacity) {
        int n = weights.length;
        int[][] dp = new int[n+1][capacity+1];
        for (int i = 1; i <= n; i++) {
            for (int w = 0; w <= capacity; w++) {
                // Don't take item i-1
                dp[i][w] = dp[i-1][w];
                // Take item i-1 if it fits
                if (weights[i-1] <= w) {
                    // TODO: dp[i][w] = Math.max(dp[i][w], values[i-1] + dp[i-1][w-weights[i-1]])
                }
            }
        }
        return dp[n][capacity];
    }

    public List<Integer> selectedItems(int[] weights, int[] values, int capacity) {
        int n = weights.length;
        int[][] dp = new int[n+1][capacity+1];
        for (int i=1;i<=n;i++) for (int w=0;w<=capacity;w++) {
            dp[i][w]=dp[i-1][w];
            if(weights[i-1]<=w) dp[i][w]=Math.max(dp[i][w],values[i-1]+dp[i-1][w-weights[i-1]]);
        }
        List<Integer> taken = new ArrayList<>();
        int w = capacity;
        for (int i=n;i>0;i--) {
            if (dp[i][w] != dp[i-1][w]) { taken.add(i-1); w -= weights[i-1]; }
        }
        Collections.reverse(taken);
        return taken;
    }

    public static void main(String[] args) {
        KnapsackTabulation kt = new KnapsackTabulation();
        int[] w = {1, 3, 4, 5};
        int[] v = {1, 4, 5, 7};
        System.out.println("Max value (cap=7): " + kt.maxValue(w, v, 7));
        System.out.println("Items selected:    " + kt.selectedItems(w, v, 7));
        System.out.println("Max value (cap=5): " + kt.maxValue(w, v, 5));
        System.out.println("Items selected:    " + kt.selectedItems(w, v, 5));
    }
}
